import React from "react";
import { motion } from "framer-motion";
import { FaHeart } from "react-icons/fa";

const HomeAboutSection = () => {
  return (
    <motion.div
      className="container my-5"
      initial={{ opacity: 0, y: 50 }}
      whileInView={{ opacity: 1, y: 0 }}
      transition={{ duration: 1 }}
      viewport={{ once: true }}
    >
      <div className="row align-items-center">
        {/* ✅ مساحة الصورة */}
        <div className="col-md-5 text-center mb-4 mb-md-0">
          {/* هتحط صورة هنا بعدين */}
          <img
            src="/path/to/about-image.jpg"
            alt="فريق صناع الحياة"
            className="img-fluid rounded shadow"
          />
        </div>

        {/* ✅ الكلام */}
        <div className="col-md-7">
          <h3 className="text-primary font-weight-bold mb-3 d-flex align-items-center justify-content-center justify-content-md-start">
            <FaHeart className="text-warning mr-2" size={24} />
            <span>إحنا مين؟</span>
          </h3>
          <p className="lead text-muted" style={{ lineHeight: "1.8" }}>
            إحنا شباب من الإسماعيلية، قررنا نغيّر ونفيد مجتمعنا على قد ما نقدر.  
            بنشتغل تحت مظلة <strong>صناع الحياة مصر</strong>،  
            أكبر كيان شبابي تطوعي في الوطن العربي،  
            وهدفنا الأساسي هو تنمية الإنسان ومساعدة كل محتاج.
            <br />
            بنشتغل في مجالات مختلفة زي التعليم، الصحة، التوعية، الدعم النفسي، والمساعدات الإنسانية.
            <br />
            لو عندك وقت تحب تديه لغيرك... إحنا مستنيينك تكون معانا ❤
          </p>
        </div>
      </div>
    </motion.div>
  );
};

export default HomeAboutSection;
